import assert from 'assert'
import { geo, geoFromHeaders, isInRegion, geoDistance } from './geo'

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function makeHeaders(entries: Record<string, string>): Headers {
  return new Headers(entries)
}

// ---------------------------------------------------------------------------
// geo() - Vercel headers
// ---------------------------------------------------------------------------

{
  const headers = makeHeaders({
    'x-vercel-ip-city': 'New York',
    'x-vercel-ip-country': 'US',
    'x-vercel-ip-country-region': 'NY',
    'x-vercel-ip-latitude': '40.7128',
    'x-vercel-ip-longitude': '-74.0060',
    'x-vercel-ip-timezone': 'America/New_York',
  })

  const result = geo({ headers })

  assert.strictEqual(result.city, 'New York', 'city from x-vercel-ip-city')
  assert.strictEqual(result.countryCode, 'US', 'countryCode from x-vercel-ip-country')
  assert.strictEqual(result.country, 'United States', 'country name derived from countryCode')
  assert.strictEqual(result.region, 'NY', 'region from x-vercel-ip-country-region')
  assert.strictEqual(result.latitude, '40.7128', 'latitude from x-vercel-ip-latitude')
  assert.strictEqual(result.longitude, '-74.0060', 'longitude from x-vercel-ip-longitude')
  assert.strictEqual(result.timezone, 'America/New_York', 'timezone from x-vercel-ip-timezone')
}

// ---------------------------------------------------------------------------
// geoFromHeaders() - Cloudflare fallback for countryCode
// ---------------------------------------------------------------------------

{
  const headers = makeHeaders({
    'cf-ipcountry': 'GB',
  })

  const result = geoFromHeaders(headers)

  assert.strictEqual(result.countryCode, 'GB', 'countryCode falls back to cf-ipcountry')
  assert.strictEqual(result.country, 'United Kingdom', 'country name from Cloudflare header')
  assert.strictEqual(result.city, undefined, 'city is undefined when header absent')
  assert.strictEqual(result.region, undefined, 'region is undefined when header absent')
}

// Vercel header takes precedence over Cloudflare header
{
  const headers = makeHeaders({
    'x-vercel-ip-country': 'DE',
    'cf-ipcountry': 'FR',
  })

  const result = geoFromHeaders(headers)
  assert.strictEqual(result.countryCode, 'DE', 'x-vercel-ip-country takes precedence over cf-ipcountry')
  assert.strictEqual(result.country, 'Germany', 'country name matches precedent header')
}

// ---------------------------------------------------------------------------
// Missing headers return undefined fields
// ---------------------------------------------------------------------------

{
  const headers = makeHeaders({})
  const result = geo({ headers })

  assert.strictEqual(result.city, undefined, 'city undefined with no headers')
  assert.strictEqual(result.country, undefined, 'country undefined with no headers')
  assert.strictEqual(result.countryCode, undefined, 'countryCode undefined with no headers')
  assert.strictEqual(result.region, undefined, 'region undefined with no headers')
  assert.strictEqual(result.latitude, undefined, 'latitude undefined with no headers')
  assert.strictEqual(result.longitude, undefined, 'longitude undefined with no headers')
  assert.strictEqual(result.timezone, undefined, 'timezone undefined with no headers')
}

// ---------------------------------------------------------------------------
// Country name lookup
// ---------------------------------------------------------------------------

const countryCases: Array<[string, string]> = [
  ['AU', 'Australia'],
  ['BR', 'Brazil'],
  ['CA', 'Canada'],
  ['CN', 'China'],
  ['DE', 'Germany'],
  ['FR', 'France'],
  ['GB', 'United Kingdom'],
  ['IN', 'India'],
  ['JP', 'Japan'],
  ['US', 'United States'],
]

for (const [code, name] of countryCases) {
  const result = geoFromHeaders(makeHeaders({ 'x-vercel-ip-country': code }))
  assert.strictEqual(result.country, name, `country name for ${code}`)
}

// Unknown code -> country is undefined
{
  const result = geoFromHeaders(makeHeaders({ 'x-vercel-ip-country': 'ZZ' }))
  assert.strictEqual(result.country, undefined, 'unknown countryCode yields undefined country')
}

// ---------------------------------------------------------------------------
// isInRegion()
// ---------------------------------------------------------------------------

{
  const g = { countryCode: 'US' }
  assert.strictEqual(isInRegion(g, ['US', 'CA']), true, 'US is in [US, CA]')
  assert.strictEqual(isInRegion(g, ['us', 'ca']), true, 'case-insensitive match (lowercase list)')
  assert.strictEqual(isInRegion(g, ['DE', 'FR']), false, 'US is not in [DE, FR]')
  assert.strictEqual(isInRegion(g, []), false, 'empty list returns false')
}

{
  const g = { countryCode: undefined }
  assert.strictEqual(isInRegion(g, ['US']), false, 'undefined countryCode returns false')
}

// ---------------------------------------------------------------------------
// geoDistance() - Haversine
// ---------------------------------------------------------------------------

// New York (40.7128, -74.0060) to London (51.5074, -0.1278) ≈ 5570 km
{
  const dist = geoDistance('40.7128', '-74.0060', '51.5074', '-0.1278')
  assert.ok(
    Math.abs(dist - 5570) < 50,
    `New York to London expected ~5570 km, got ${dist.toFixed(1)} km`
  )
}

// Same point -> 0 km
{
  const dist = geoDistance('35.6895', '139.6917', '35.6895', '139.6917')
  assert.strictEqual(dist, 0, 'same coordinates yield 0 km')
}

// Sydney (−33.8688, 151.2093) to Tokyo (35.6895, 139.6917) ≈ 7823 km
{
  const dist = geoDistance('-33.8688', '151.2093', '35.6895', '139.6917')
  assert.ok(
    Math.abs(dist - 7823) < 50,
    `Sydney to Tokyo expected ~7823 km, got ${dist.toFixed(1)} km`
  )
}

console.log('All geo tests passed.')

